// shouldCompact returns true if the context usage exceeds the auto-compact threshold.
func (a *agent) shouldCompact(usedTokens int64) bool {
    cfg := config.Get()
    agentCfg, ok := cfg.Agents[a.agentName]
    if !ok || !agentCfg.AutoCompact {
        return false
    }
    threshold := agentCfg.AutoCompactThreshold
    if threshold <= 0 {
        threshold = 0.85 // default
    }
    contextWindow := a.provider.Model().ContextWindow
    if contextWindow <= 0 {
        return false
    }
    return float64(usedTokens) >= float64(contextWindow)*threshold
}
```

#### 2b. Add a `compactContext` method

This method:
1. Gets all messages for the session
2. If there are fewer than 4 messages, skip (not worth compacting)
3. Keeps the last 2 messages (most recent exchange) as "tail"
4. Sends the older messages to the summarizer provider with the compaction prompt
5. Replaces the session messages: saves a single "system" message with the summary + the tail messages
6. Returns the new message count

```go
func (a *agent) compactContext(ctx context.Context, sessionID string) error {
    if a.summarizeProvider == nil {
        return fmt.Errorf("no summarizer provider available for compaction")
    }

    msgs, err := a.messages.List(ctx, sessionID)
    if err != nil {
        return fmt.Errorf("failed to list messages for compaction: %w", err)
    }

    if len(msgs) < 4 {
        return nil // not enough messages to compact
    }

    // Keep last 2 messages as tail (most recent exchange)
    tailStart := len(msgs) - 2
    toSummarize := msgs[:tailStart]
    tail := msgs[tailStart:]

    // Build conversation text for summarization
    var convText strings.Builder
    for _, msg := range toSummarize {
        role := "User"
        if msg.Role == message.Assistant {
            role = "Assistant"
        }
        convText.WriteString(fmt.Sprintf("\n\n%s: %s", role, msg.Content().String()))
    }

    // Compaction prompt (from Claude Code analysis)
    compactionSystemPrompt := `Create a structured summary of the conversation to replace the conversation history. Include:
1. Task Overview: user's core request, success criteria, any constraints
2. Current State: completed work, files modified (with paths), key outputs produced
3. Important Discoveries: technical constraints, decisions made, errors resolved
4. Next Steps: remaining work, pending decisions or blockers

Be concise but complete. This summary will replace the conversation history.`

    summaryResponse, err := a.summarizeProvider.SendMessages(
        ctx,
        []message.Message{
            {
                Role:  message.User,
                Parts: []message.ContentPart{message.TextContent{Text: compactionSystemPrompt + "\n\nConversation to summarize:\n" + convText.String()}},
            },
        },
        []tools.BaseTool{},
    )
    if err != nil {
        return fmt.Errorf("failed to generate compaction summary: %w", err)
    }

    summary := summaryResponse.Content
    summaryMsg := fmt.Sprintf("The following is a summary of the earlier conversation:\n\n%s\n\n---\nConversation continues below:", summary)

    // Delete old messages and re-save: summary + tail
    // Use whatever message deletion API exists
    // Then save: one assistant message with the summary, then the tail messages
    // Check the messages.Service interface for available methods

    logging.InfoPersist(fmt.Sprintf("Context compacted: %d messages → summary + %d tail messages", len(toSummarize), len(tail)))
    return a.rebuildSessionMessages(ctx, sessionID, summaryMsg, tail)
}
```

#### 2c. Add `rebuildSessionMessages` method

Look at the `message.Service` interface to understand what methods are available for saving/deleting messages. Implement rebuilding the session with:
- One "assistant" message containing the summary text (or look at how system messages work)
- Then the tail messages

#### 2d. Integrate into the agent run loop

In `processGeneration` (or wherever streaming responses are processed and token usage is tracked), after receiving each response:

```go
// After getting response with usage stats:
if usage := response.Usage; a.shouldCompact(usage.InputTokens + usage.OutputTokens) {
    // Emit a warning event about compaction
    a.publishEvent(AgentEvent{
        Type:  AgentEventTypeResponse,
        Delta: "\n\n⚡ Auto-compacting context to free space...\n",
    })
    if err := a.compactContext(ctx, sessionID); err != nil {
        logging.Warn("Context compaction failed", "error", err)
    } else {
        a.publishEvent(AgentEvent{
            Type:  AgentEventTypeResponse,  
            Delta: "✓ Context compacted. Continuing...\n\n",
        })
    }
}
```

### 3. Also handle the `context_window_exceeded` error

In the existing error handling (where API errors are retried), add handling for when the error is a context window exceeded error:
